class MicroMindClassifier(BaseEstimator, ClassifierMixin):
    """
    Classifier that implements the Microsegment discovery logic for Tic-Tac-Toe.
    It uses a set of 186 rules discovered by MicroMind AI to classify game states.
    """
    def __init__(self):
        self.classes_ = ['negative', 'positive']
        
    def fit(self, X, y):
        # El modelo es basado en reglas fijas, no requiere entrenamiento
        return self
        
    def predict(self, X):
        if isinstance(X, np.ndarray):
            X = pd.DataFrame(X, columns=['top-left-square', 'top-middle-square', 'top-right-square', 
                                       'middle-left-square', 'middle-middle-square', 'middle-right-square', 
                                       'bottom-left-square', 'bottom-middle-square', 'bottom-right-square'])
        
        predictions = X.apply(classify_row, axis=1)
        # Mapear "Segmento X" a "positive" y "Sin Segmento" a "negative"
        return np.array(['positive' if p != 'Sin Segmento' else 'negative' for p in predictions])

    def predict_proba(self, X):
        # Dummy probabilities: 1.0 for the predicted class
        preds = self.predict(X)
        proba = np.zeros((len(preds), 2))
        for i, p in enumerate(preds):
            if p == 'positive':
                proba[i, 1] = 1.0
            else:
                proba[i, 0] = 1.0
        return proba

